class ThemeSettings(TlObject):
    r"""Describes theme settings

    Parameters:
        base_theme (:class:`~pytdbot.types.BuiltInTheme`):
            Base theme for this theme

        accent_color (:class:`int`):
            Theme accent color in ARGB format

        background (:class:`~pytdbot.types.Background`):
            The background to be used in chats; may be null

        outgoing_message_fill (:class:`~pytdbot.types.BackgroundFill`):
            The fill to be used as a background for outgoing messages; may be null if the fill from the base theme must be used instead

        animate_outgoing_message_fill (:class:`bool`):
            If true, the freeform gradient fill needs to be animated on every sent message

        outgoing_message_accent_color (:class:`int`):
            Accent color of outgoing messages in ARGB format

    """

    def __init__(
        self,
        *,
        base_theme: BuiltInThemeClassic
        | BuiltInThemeDay
        | BuiltInThemeNight
        | BuiltInThemeTinted
        | BuiltInThemeArctic
        | None = None,
        accent_color: int | None = 0,
        background: Background | None = None,
        outgoing_message_fill: BackgroundFillSolid
        | BackgroundFillGradient
        | BackgroundFillFreeformGradient
        | None = None,
        animate_outgoing_message_fill: bool | None = False,
        outgoing_message_accent_color: int | None = 0,
    ) -> None:
        self.base_theme = base_theme
        r"""Base theme for this theme"""
        self.accent_color = accent_color
        r"""Theme accent color in ARGB format"""
        self.background = background
